1) 파일: supabase/migrations/20260504000002_create_categories.sql
2) 주요 SQL:
   CREATE TABLE IF NOT EXISTS public.categories (
     id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
     slug TEXT NOT NULL UNIQUE,
     name TEXT NOT NULL,
     type TEXT NOT NULL CHECK (type IN ('topic','campus')),
     sort_order INTEGER NOT NULL DEFAULT 0,
     is_active BOOLEAN NOT NULL DEFAULT true,
     created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
     updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
   );
   CREATE INDEX IF NOT EXISTS idx_categories_type_sort ON public.categories (type, sort_order);
   ALTER TABLE public.categories ENABLE ROW LEVEL SECURITY;
3) RLS 4정책 (DROP IF EXISTS + CREATE 패턴으로 idempotent):
   DROP POLICY IF EXISTS categories_select_all ON public.categories;
   CREATE POLICY categories_select_all ON public.categories FOR SELECT USING (true);
   DROP POLICY IF EXISTS categories_insert_admin ON public.categories;
   CREATE POLICY categories_insert_admin ON public.categories FOR INSERT WITH CHECK (public.is_admin());
   DROP POLICY IF EXISTS categories_update_admin ON public.categories;
   CREATE POLICY categories_update_admin ON public.categories FOR UPDATE USING (public.is_admin()) WITH CHECK (public.is_admin());
   DROP POLICY IF EXISTS categories_delete_admin ON public.categories;
   CREATE POLICY categories_delete_admin ON public.categories FOR DELETE USING (public.is_admin());
4) 트리거: DROP TRIGGER IF EXISTS categories_set_updated_at ON public.categories; CREATE TRIGGER categories_set_updated_at BEFORE UPDATE ON public.categories FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
5) mcp__supabase__apply_migration name='create_categories' query=<위 SQL>

1) Write 로 20260504000008_create_counter_triggers.sql 생성:

   CREATE OR REPLACE FUNCTION public.reactions_apply_post_counter() RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
   BEGIN
     IF TG_OP='INSERT' AND NEW.target_type='post' THEN
       UPDATE posts SET reaction_up   = reaction_up   + (NEW.reaction='up')::int,
                        reaction_down = reaction_down + (NEW.reaction='down')::int
        WHERE id = NEW.target_id;
     ELSIF TG_OP='DELETE' AND OLD.target_type='post' THEN
       UPDATE posts SET reaction_up   = GREATEST(0, reaction_up   - (OLD.reaction='up')::int),
                        reaction_down = GREATEST(0, reaction_down - (OLD.reaction='down')::int)
        WHERE id = OLD.target_id;
     ELSIF TG_OP='UPDATE' AND NEW.target_type='post' AND OLD.reaction <> NEW.reaction THEN
       UPDATE posts SET reaction_up   = GREATEST(0, reaction_up   + (NEW.reaction='up')::int   - (OLD.reaction='up')::int),
                        reaction_down = GREATEST(0, reaction_down + (NEW.reaction='down')::int - (OLD.reaction='down')::int)
        WHERE id = NEW.target_id;
     END IF;
     RETURN NULL;
   END $$;

   DROP TRIGGER IF EXISTS reactions_after_change ON reactions;
   CREATE TRIGGER reactions_after_change AFTER INSERT OR UPDATE OR DELETE ON reactions FOR EACH ROW EXECUTE FUNCTION reactions_apply_post_counter();

   CREATE OR REPLACE FUNCTION public.comments_apply_post_counter() RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
   BEGIN
     IF TG_OP='INSERT' AND NEW.is_deleted=false THEN UPDATE posts SET comment_count = comment_count + 1 WHERE id = NEW.post_id;
     ELSIF TG_OP='DELETE' AND OLD.is_deleted=false THEN UPDATE posts SET comment_count = GREATEST(0, comment_count - 1) WHERE id = OLD.post_id;
     ELSIF TG_OP='UPDATE' AND OLD.is_deleted IS DISTINCT FROM NEW.is_deleted THEN
       IF NEW.is_deleted THEN UPDATE posts SET comment_count = GREATEST(0, comment_count - 1) WHERE id = NEW.post_id;
       ELSE UPDATE posts SET comment_count = comment_count + 1 WHERE id = NEW.post_id; END IF;
     END IF;
     RETURN NULL;
   END $$;

   DROP TRIGGER IF EXISTS comments_after_change ON comments;
   CREATE TRIGGER comments_after_change AFTER INSERT OR UPDATE OR DELETE ON comments FOR EACH ROW EXECUTE FUNCTION comments_apply_post_counter();

   COMMENT 함수 2종 + 헤더 주석 (target_type 변경 UPDATE 는 application 차단 가정 / comments 의 reactions 카운터는 본 Task 범위 밖)

